            """);

        await DatabaseSchemaHelper.TryAddColumnAsync(db, "Companies", "BusinessTypesJson", "TEXT NOT NULL DEFAULT '[]'");
        await DatabaseSchemaHelper.TryAddColumnAsync(db, "Companies", "VendorPolicyTagsJson", "TEXT NOT NULL DEFAULT '[]'");
