        await DatabaseSchemaHelper.TryAddColumnAsync(db, "Vendors", "ProductPolicyTag", "TEXT NOT NULL DEFAULT 'non-halal'");
        await DatabaseSchemaHelper.EnsureColumnAsync(db, "PurchaseOrderItems", "HalalCertNo", "TEXT NOT NULL DEFAULT ''");

        await db.Database.ExecuteSqlRawAsync("""
            UPDATE "Vendors"
            SET "ProductPolicyTag" = 'non-halal'
            WHERE LOWER("Name" || ' ' || "Products") LIKE '%wine%'
               OR LOWER("Name" || ' ' || "Products") LIKE '%spirit%'
               OR LOWER("Name" || ' ' || "Products") LIKE '%beer%'
               OR LOWER("Name" || ' ' || "Products") LIKE '%pork%';
            """);

        await db.Database.ExecuteSqlRawAsync("""
            UPDATE "Vendors"
            SET "ProductPolicyTag" = 'halal'
            WHERE "ProductPolicyTag" IS NULL
               OR TRIM("ProductPolicyTag") = ''
               OR "ProductPolicyTag" = 'non-halal'
                  AND NOT (
                    LOWER("Name" || ' ' || "Products") LIKE '%wine%'
                    OR LOWER("Name" || ' ' || "Products") LIKE '%spirit%'
                    OR LOWER("Name" || ' ' || "Products") LIKE '%beer%'
                    OR LOWER("Name" || ' ' || "Products") LIKE '%pork%'
